var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……지진?","JPN":"……地震？","ENG":"...An earthquake?","TWN":"……地震？"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"당장 알아보겠습니다.","JPN":"すぐ調べてきます。","ENG":"I’ll go take a look.","TWN":"我們立刻去看看！"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래요. 정말, 빨리 헤이븐 랜드로 올라가야지 안 되겠네. 여러모로 귀찮은 일이 계속……","JPN":"お願いします。もう、早くヘイブンランドに戻らないといけないわね。次々と面倒なことが……","ENG":"All right then. I should head back up to Havenland soon. It’s just one annoying thing after─","TWN":"嗯嗯，我還得趕快上去天堂樂園呢。真是的，麻煩的事一大堆……"},"stage":{"bg":"PRISON_NIGHT_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"한 번에 뚫릴 줄 알았는데. 이건 너무 멋없잖아?","JPN":"一度であくと思ったのに。これちょっとカッコ悪くない？","ENG":"Bummer. I thought I could take it out in one blow.","TWN":"我還以為一腳就可以踹破，結果一點也不帥！"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도로시…… 충분히 멋있긴 한데…… 꼭 이렇게 요란하게 했어야 됐을까?","JPN":"ドロシーちゃん……十分カッコよかったけど……ここまで派手にやる必要があったの？","ENG":"Dorothy... That was pretty cool and all, but... Did we have to make a scene?","TWN":"桃樂絲……帥是很帥…不過你非得動作這麼大嗎？"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"쉬이. 토토. 벼, 별일 아냐! 잠깐 큰소리가 난 것뿐이니까 진정해.","JPN":"シーっ。トト。た、大したことじゃないよ！　ちょっと大きな音がしただけだから落ち着いて。","ENG":"Shh, Toto. I-it’s nothing, so calm down. The loud noise is gone now.","TWN":"噓，托托，沒事沒事！只是聲音有點大而已，你別激動。"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이럴 줄 알았으면 빈말이라도 네가 해결해 보라는 얘긴 안 했을 텐데.","JPN":"こうなると知ってたら、お世辞にもアナタに解決してみろという話はしなかったのに。","ENG":"I would have never asked you if I had known this was going to happen.","TWN":"早知如此，我就不假裝客氣讓你去處理。"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"문 해킹하는 시간이 얼마나 걸린다고. 그 짧은 시간도 기다리기가 그렇게 어려웠어?","JPN":"扉なんて瞬く間にハッキングできるんだ。その短い時間も待てなかった？","ENG":"It would have only taken a few minutes to hack the door. You couldn't wait a few minutes?","TWN":"駭入門鎖是要花多少時間，你連這麼短的時間都等不及嗎？"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이렇게 하면 금방 들어오는데 뭐하러?","JPN":"こうやったらすぐ入れるのになんで？","ENG":"I busted it wide open in no time, so why bother?","TWN":"那麼麻煩幹嘛，這樣用踹的不是很快嗎？"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그래. 덕분에 아주 온 난리 다 피워서 지원팀 다 몰려오게 생겼지만.","JPN":"そうだね。おかげさまで、騒ぎすぎて応援班が全部押し寄せてきそうだけど。","ENG":"Yeah. Thanks to you, all the support team will be running over here.","TWN":"是很快，但也拜你所賜，引起這麼大的騷動，現在整個支援組都知道我們在這。"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"싸우지 마, 얘들아. 지금 그럴 때야?","JPN":"みんな、ケンカしないで。そういう場合じゃないでしょ？","ENG":"Girls, don’t fight. We don’t have time for that.","TWN":"你們不要吵架，現在是吵架的時候嗎？"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"메이드 언니 몰래 와서 가슴 쫄려 죽겠는데…….","JPN":"メイドのお姉さんに黙って、こっそり来たから気が気じゃないのに……","ENG":"I’m just worried about what the maid will do to us if she finds out...","TWN":"瞞著女僕姊姊跑到這裡來，我都已經快緊張死了……"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그건 걱정 마. 허락만 못 받았지, 다른 건 다 받은 거나 마찬가지니까.","JPN":"それは心配すんなよ。取れなかったのは許可だけで、他のものは全部取ったようなもんだから。","ENG":"Don’t worry. She may not have granted us permission, but she did grant us everything else.","TWN":"你放心啦，她只是嘴上沒說，但其實是默許。"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"오늘은 다른 때보다 밤이 긴 날이라 다들 헤이븐 랜드에 올라가서 비어 있을 거랬고, 위저드 좌표도 정확하게 찍어 줬어.","JPN":"今日はいつもより夜が長い日だから、みんなヘイブンランドに上がっていて手薄だろうって言っていたし、ウィザードの座標も正確に示してくれた。","ENG":"She gave us the exact coordinates and even told us that it would be mostly empty because everyone would be up in Havenland because the night was longer than usual.","TWN":"她說今天的夜特別長，大家一定會上天堂樂園，組織裡一定沒人的，還告訴我們魔法師的座標。"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이 정도 알려준 거면 분명 몰래 침입하라는 얘기야.","JPN":"ここまで教えてくれたってことは、きっとこっそり侵入してもいいってこと。","ENG":"If she told us that much, she wanted us to infiltrate this place.","TWN":"她跟我們說這麼多，擺明是要我們偷偷潛入的意思。"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그건 아닐 것 같은데…….","JPN":"それは違うと思うよ……","ENG":"I don’t think so...","TWN":"應該不是吧……"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"치사하게 우리만 빼놓고 작전 진행할 생각이었다니까? 침입 명단에 우리 셋 이름만 쏙 빠져 있었거든.","JPN":"私たちなしで作戦を進める気だったんだ、ズルくない？　侵入リストに私たち3人の名前だけなかったんだ。","ENG":"She was trying to hog the mission all to herself. She even left our names off the infiltration list.","TWN":"就說她是將我們排除在作戰之外！入侵名單中偏偏就沒有我們三個人的名字。"},"stage":{"bg":"NIGHTMARE_02","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};